#include<cstdio>
#include<algorithm>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
typedef long long LL;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=2e5+10;struct node{int a,b,c;}t[N];int n,m,a[N],T[N],loc[N];LL cnt[N],S[N];
inline bool cmpa(const node&x,const node&y){return x.a==y.a?(x.b==y.b?x.c<y.c:x.b<y.b):x.a<y.a;}
inline bool cmpb(const node&x,const node&y){return x.b==y.b?x.c<y.c:x.b<y.b;}
LL BIT[N];inline void add(int p,const LL &w){while(p<=n)BIT[p]+=w,p+=(p&-p);}
inline LL qry(int p){LL res=0;while(p)res+=BIT[p],p^=(p&-p);return res;}
inline void cdq(const int &l,const int &r)
{
	if(l==r)return;const int &mid=(l+r)>>1;
	cdq(l,mid);cdq(mid+1,r);
	std::sort(t+l,t+mid+1,cmpb);
	std::sort(t+mid+1,t+r+1,cmpb);
	int pl=l,pr=mid+1;while(pr<=r)
	{
		while(pl<=mid&&t[pl].b<t[pr].b)add(t[pl++].c,1);
		cnt[t[pr].a]+=qry(t[pr].c);++pr;
	}
	for(int i=l;i<pl;++i)add(t[i].c,-1);
}
inline void Solve(){std::sort(t+1,t+n+1,cmpa);cdq(1,n);}
int main()
{
//	freopen("count.in","r",stdin);
//	freopen("count.out","w",stdout);
	n=read();m=read();rep(1,n,i)loc[a[i]=read()]=i;
	rep(1,m,i)T[loc[read()]]=i;int tmp=m;rep(1,n,i)if(!T[i])T[i]=++tmp;
	rep(1,n,i)t[i].a=n-i+1,t[i].b=a[i],t[i].c=n-T[i]+1;Solve();
	rep(1,n>>1,i){int tmp=cnt[i];cnt[i]=cnt[n-i+1];cnt[n-i+1]=tmp;}
	rep(1,n,i)t[i].a=i,t[i].b=n-a[i]+1,t[i].c=n-T[i]+1;Solve();
	rep(1,n,i)S[T[i]]=cnt[i];drep(n-1,1,i)S[i]+=S[i+1];
	rep(1,m,i)printf("%lld\n",S[i]); return 0;
}
